"""
Gera dinamicamente o JSON de campos para o próximo node Form, com base na
entrada vinda do form anterior + mapeamento já aplicado no node Python
(`projeto_id`, `nome`, `nome_completo`).

Entrada esperada (exemplo):
[
  {
    "Selecione o produto desejado": "Wagtail",
    "submittedAt": "2025-10-23T11:50:36.173-03:00",
    "formMode": "test",
    "projeto_id": 256,
    "nome": "Squad Wagtail",
    "nome_completo": "Logbit - Squad Wagtail"
  }
]

Saída: item único por entrada, contendo:
- `fields`: array (objeto) com os campos no formato aceito pelo node Form (defineForm=json)
- `fieldsString`: string JSON, pronta para colar no node Form

Regras:
- Se `projeto_id` == 0: exibe aviso (HTML) e checkbox "Escolher outro produto".
- Caso contrário: exibe dropdown "Selecione o projeto" com as opções pelo nome.
  - Quando houver apenas 1 opção, o dropdown contém apenas essa opção (single select).
"""

import json


def to_dict(maybe_proxy):
    try:
        return maybe_proxy.to_py()
    except Exception:
        return maybe_proxy


def build_fields_from_item(data):
    projeto_id = data.get("projeto_id")
    nome = data.get("nome")
    nome_completo = data.get("nome_completo")

    try:
        projeto_id_int = int(projeto_id) if projeto_id is not None else 0
    except Exception:
        projeto_id_int = 0

    # Caso sem iniciativa associada ao produto
    if projeto_id_int == 0:
        return [
            {
                "fieldType": "html",
                "elementName": "aviso_sem_iniciativas",
                "html": (
                    "<div style=\"padding:8px 12px; border:1px solid #f6dcb7; "
                    "background:#fefaf6; color:#e6a23d; border-radius:6px;\">"
                    "Ainda não foram associadas iniciativas nesse produto."
                    "</div>"
                ),
            },
            {
                "fieldLabel": "Escolher outro produto",
                "fieldType": "checkbox",
                "fieldOptions": {
                    "values": [
                        {"option": "Sim"}
                    ]
                },
            },
        ]

    # Com iniciativa(s): montar dropdown com os nomes disponíveis
    option_label = None
    if isinstance(nome, str) and nome.strip():
        option_label = nome.strip()
    elif isinstance(nome_completo, str) and nome_completo.strip():
        # fallback amigável
        option_label = nome_completo.strip()
    else:
        option_label = f"Projeto {projeto_id_int}"

    fields = [
        {
            "fieldLabel": "Selecione a iniciativa",
            "fieldType": "dropdown",
            "fieldOptions": {
                "values": [
                    {"option": option_label}
                ]
            },
            "multiselect": False,
            "requiredField": True,
        }
    ]

    # Dropdown adicional: Concluídos vs Backlog
    fields.append(
        {
            "fieldLabel": "Selecione a fase para análise",
            "fieldType": "dropdown",
            "fieldOptions": {
                "values": [
                    {"option": "Backlog"},
                    {"option": "Concluídos"}
                ]
            },
            "multiselect": False,
            "requiredField": True,
        }
    )

    return fields


out_items = []
for item in _input.all():
    data = to_dict(getattr(item, "json", {}))
    if not isinstance(data, dict):
        data = {}

    fields = build_fields_from_item(data)
    payload = {
        "fields": fields,
        # Conveniência: string pronta para copiar e colar no node Form
        "fieldsString": json.dumps(fields, ensure_ascii=False, indent=2),
    }
    out_items.append({"json": payload})

return out_items

