// Code (JavaScript) – e-mail dinâmico com análises preditivas
// ---------- 1) Entrada ----------
const g = $json.data?.resultado || {};
const cards = Array.isArray(g.cards) ? g.cards : [];

const selReq = ($json.backlog_reqs && typeof $json.backlog_reqs === "object") ? $json.backlog_reqs : {};
const selMet = ($json.backlog_metricas && typeof $json.backlog_metricas === "object") ? $json.backlog_metricas : {};

// ---------- 2) Helpers ----------
const fmt = (n, d = 2) => (n == null || isNaN(n)) ? "-" :
  Number(n).toLocaleString("pt-BR", { minimumFractionDigits: d, maximumFractionDigits: d });

const toNum = (v) => (v == null ? null : Number(v));

const parseHHMMSSHours = (s) => {
  if (!s || typeof s !== "string") return 0;
  const [hh, mm, ss] = s.split(":").map(Number);
  if ([hh, mm, ss].some(x => !Number.isFinite(x))) return 0;
  return hh + (mm / 60) + (ss / 3600);
};

const toPct = (raw, decimals = 0) => {
  if (!Number.isFinite(raw)) return "-";
  const pct = raw <= 1 ? raw * 100 : (raw <= 10 ? raw * 10 : raw);
  return `${pct.toFixed(decimals)}%`;
};

// ---------- 3) Derivados por card ----------
function deriveReqFlags(card) {
  const av = card.alertas_validacao || {};
  const aged =
    (Array.isArray(card.alertas) && card.alertas.some(a => a?.tipo === "backlog_estagnado" && Number(a?.dias) > 7)) ||
    av.card_antigo_sem_priorizacao === true;

  const horasAndamento = parseHHMMSSHours(card.tempo_decorrido);
  const longRun = (card.em_andamento === true && horasAndamento > 10);

  return {
    titulo_presente: !av.sem_titulo,
    descricao_presente: !av.sem_descricao,
    responsaveis_definidos: !av.sem_responsaveis,
    tags_definidas_e_descritivas: !av.sem_tags && !av.tags_pouco_descritivas,
    estimativa_de_esforco: !av.sem_estimativa_esforco,
    pontos_totais_do_card: !av.sem_pontos,
    data_de_criacao: !av.sem_data_criacao,
    data_prevista: !av.sem_data_prevista && !av.data_prevista_antes_criacao,
    data_desejada: !av.sem_data_desejada,
    descricao_completa: !av.descricao_curta && !av.sem_criterios_aceite,
    vinculo_ao_projeto: !av.sem_vinculo_projeto,
    alertas_de_idade_do_card: aged,
    alertas_de_tempo_de_andamento: longRun,
  };
}

// ---------- 4) Duplicados ----------
const dupPairs = [];
(g.alertas_gerais || []).forEach(entry => {
  const arr = entry?.similaridade_titulo;
  if (Array.isArray(arr)) arr.forEach(p => dupPairs.push(p));
});

const dupCardIds = new Set();
dupPairs.forEach(p => {
  const cs = Array.isArray(p.cards) ? p.cards : [];
  cs.forEach(pair => {
    const id = Array.isArray(pair) ? pair[0] : null;
    if (id != null) dupCardIds.add(id);
  });
});

const possiveisDuplicados = dupPairs.map(p => {
  const [a, b] = p.cards || [];
  const sA = Array.isArray(a) ? `#${a[0]} – ${a[1]}` : String(a ?? "");
  const sB = Array.isArray(b) ? `#${b[0]} – ${b[1]}` : String(b ?? "");
  const simTxt = toPct(Number(p.grau_de_similaridade), 0);
  return `${sA} ↔ ${sB} (sim: ${simTxt})`;
});

// ---------- 5) Seleção dinâmica ----------
const ALL_REQ = [
  "titulo_presente", "descricao_presente", "responsaveis_definidos",
  "tags_definidas_e_descritivas", "estimativa_de_esforco", "pontos_totais_do_card",
  "data_de_criacao", "data_prevista", "data_desejada", "descricao_completa",
  "vinculo_ao_projeto", "alertas_de_idade_do_card", "alertas_de_tempo_de_andamento",
  "deteccao_de_similares"
];

const hasReqConfig = Object.keys(selReq).length > 0;
const selectedReq = hasReqConfig ? Object.keys(selReq).filter(k => selReq[k]) : [];
const REQS_TO_SHOW = hasReqConfig ? selectedReq : ALL_REQ;
const COUNT_DUP_MODE = "cards";

const PRETTY = {
  titulo_presente: "Título presente",
  descricao_presente: "Descrição presente",
  responsaveis_definidos: "Responsáveis definidos",
  tags_definidas_e_descritivas: "Tags definidas e descritivas",
  estimativa_de_esforco: "Estimativa de esforço (orçado)",
  pontos_totais_do_card: "Pontos totais do card",
  data_de_criacao: "Data de criação",
  data_prevista: "Data prevista",
  data_desejada: "Data desejada",
  descricao_completa: "Descrição completa (≥20 + critérios de aceite)",
  vinculo_ao_projeto: "Vínculo ao projeto",
  alertas_de_idade_do_card: "Alertas: parado > 7 dias (Backlog)",
  alertas_de_tempo_de_andamento: "Alertas: em andamento > 10 horas",
  deteccao_de_similares: COUNT_DUP_MODE === "pairs" ? "Detecção de duplicados (pares)" : "Detecção de duplicados (cards impactados)"
};

// ---------- 6) Estatísticas ----------
const derived = cards.map(deriveReqFlags);
const total = cards.length;

function reqPendentesCount(key) {
  if (key === "deteccao_de_similares") {
    return COUNT_DUP_MODE === "pairs" ? dupPairs.length : dupCardIds.size;
  }
  const isAlertKey = (key === "alertas_de_idade_do_card" || key === "alertas_de_tempo_de_andamento");
  return derived.filter(d => {
    const v = d[key];
    if (v == null) return true;
    return isAlertKey ? v === true : v === false;
  }).length;
}

const reqStats = REQS_TO_SHOW.map(key => {
  const pendentes = reqPendentesCount(key);
  const ok = Math.max(0, total - pendentes);
  return { key, label: PRETTY[key] || key, ok, pendentes, total };
});

// ---------- 7) Métricas ----------
const leadVals = cards.map(c => toNum(c.lead_time)).filter(v => Number.isFinite(v));
const leadAvg = leadVals.length ? (leadVals.reduce((a, b) => a + b, 0) / leadVals.length) : null;

const TOP_N = 5;
const topLead = (selMet.lead_time !== false) && leadVals.length
  ? [...cards].filter(c => Number.isFinite(c.lead_time))
    .sort((a, b) => b.lead_time - a.lead_time)
    .slice(0, TOP_N)
  : [];

const tempoMedioBacklog = g.metrica_qualidade?.tempo_medio_por_fase_dia ?? null;
const throughputBacklog = g.metrica_qualidade?.throughput ?? null;

// ---------- 7.5) ANÁLISES PREDITIVAS (REESCRITO) ----------
// Novo caminho de acesso: g.cards[].analise_estrategica_ia.analise_preditiva

const allPredicoes = [];

// 1. Itera sobre todos os cards para extrair as predições detalhadas
for (const card of cards) {
    // Acessa o caminho de dados para a predição do card atual
    const analisePred = card.analise_estrategica_ia?.analise_preditiva;
    
    if (analisePred && Array.isArray(analisePred.predicoes_detalhadas)) {
        // Se houver predições, mapeia e as adiciona à lista principal
        analisePred.predicoes_detalhadas.forEach(p => {
            allPredicoes.push({
                cardId: card.id, // Adiciona o ID do card para referência
                cardTitulo: card.titulo || "(sem título)",
                predicao: p // O objeto de predição em si
            });
        });
    }
}

// 2. Mapeia, Filtra e Classifica a lista única de predições
const top10Risco = allPredicoes
  .map(item => {
    const p = item.predicao;
    // Converte a porcentagem de risco para número
    const riscoStr = String(p.risco_estouro_prazo_porcentagem || "0%").replace("%", "");
    return {
      cardId: item.cardId,
      cardTitulo: item.cardTitulo,
      contexto: p.contexto_fonte || "Contexto não especificado",
      riscoPercent: parseFloat(riscoStr) || 0,
      prazoSugerido: p.prazo_sugerido_horas || "-",
      qualidadeRisco: p.qualidade_risco_medio || "N/A", // Campo que será filtrado
      ajusteEstimativa: p.ajuste_estimativa_sugerido || "-",
      justificativa: p.justificativa_da_fonte || "Sem justificativa"
    };
  })
  .filter(p => p.qualidadeRisco === "Alto risco de retrabalho")
  .sort((a, b) => b.riscoPercent - a.riscoPercent) // Classifica (ordem decrescente de Risco Percentual)
  .slice(0, 10); // Limita aos 10 primeiros

// ---------- 8) Subject ----------
const projetoNome = g.projeto?.nome || "Projeto";
const fase = g.fase || "Backlog";
const totalCards = Number.isFinite(g.total_cards) ? g.total_cards : cards.length;
const subject = `${projetoNome} – análise dinâmica (${totalCards} cards)`;

// ---------- 9) HTML ----------
const styleTable = "font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.35;color:#111;";
let html = `\
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="${styleTable}">
<tr><td style="padding:16px 0;">
  <h1 style="margin:0 0 8px 0;font-size:18px;">${projetoNome} — Análise de Cards</h1>
